-- =============================================================================
-- DomainsMode — MySQL 8 Init Script
-- Creates databases, grants privileges, creates tables, inserts 450 rows each
-- =============================================================================

-- Create databases
CREATE DATABASE IF NOT EXISTS network_1 CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
CREATE DATABASE IF NOT EXISTS network_2 CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
CREATE DATABASE IF NOT EXISTS domainsmode_ui CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;

-- Grant privileges
GRANT ALL PRIVILEGES ON network_1.* TO 'root'@'%';
GRANT ALL PRIVILEGES ON network_2.* TO 'root'@'%';
GRANT ALL PRIVILEGES ON domainsmode_ui.* TO 'root'@'%';
FLUSH PRIVILEGES;

-- =============================================================================
-- NETWORK_1 — domains table + 450 rows
-- =============================================================================
USE network_1;

CREATE TABLE domains (
    id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
    domain VARCHAR(255) NOT NULL UNIQUE,
    nameserver_1 VARCHAR(255) DEFAULT NULL,
    nameserver_2 VARCHAR(255) DEFAULT NULL,
    nameserver_3 VARCHAR(255) DEFAULT NULL,
    nameserver_4 VARCHAR(255) DEFAULT NULL,
    mx_record VARCHAR(255) DEFAULT NULL,
    a_record VARCHAR(255) DEFAULT NULL,
    created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Batch 1: .com technology domains (rows 1-50)

-- Batch 2: .net networking domains (rows 51-100)

-- Batch 3: .org organizations (rows 101-150)

-- Batch 4: .io tech startups (rows 151-200)

-- Batch 5: .dev developer domains (rows 201-250)

-- Batch 6: .bg Bulgarian domains (rows 251-300)

-- Batch 7: .eu European domains (rows 301-350)

-- Batch 8: Mixed TLDs - business domains (rows 351-400)

-- Batch 9: Mixed creative/industry domains (rows 401-450)

-- =============================================================================
-- NETWORK_2 — domains table + 450 rows (different domains)
-- =============================================================================
USE network_2;

CREATE TABLE domains (
    id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY,
    domain VARCHAR(255) NOT NULL UNIQUE,
    nameserver_1 VARCHAR(255) DEFAULT NULL,
    nameserver_2 VARCHAR(255) DEFAULT NULL,
    nameserver_3 VARCHAR(255) DEFAULT NULL,
    nameserver_4 VARCHAR(255) DEFAULT NULL,
    mx_record VARCHAR(255) DEFAULT NULL,
    a_record VARCHAR(255) DEFAULT NULL,
    created_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Batch 1: .net primary domains (rows 1-50)

-- Batch 2: .com commercial domains (rows 51-100)

-- Batch 3: .org open-source/community domains (rows 101-150)

-- Batch 4: .io SaaS/startup domains (rows 151-200)

-- Batch 5: .dev developer tools (rows 201-250)

-- Batch 6: .bg Bulgarian domains (rows 251-300)

-- Batch 7: .eu European domains (rows 301-350)

-- Batch 8: Mixed TLDs - enterprise (rows 351-400)

-- Batch 9: Mixed final batch (rows 401-450)
